			SELECT status, COUNT(*) AS count
			FROM attempts
			GROUP BY status
			ORDER BY status ASC
		`),
		client.execute({
			sql: `
				SELECT COUNT(*) AS count
				FROM claims
				WHERE claim_expires_at > ?
			`,
			args: [now],
		}),
		client.execute(`
			SELECT
				id,
				run_id,
				attempt_id,
				level,
				type,
				message,
				data_json,
				created_at
			FROM events
			ORDER BY created_at DESC
			LIMIT 20
		`),
	]);

