	};

	const mixed = classifyRepair({
		...summary,
		checkRuns: [
			{
				name: "format check",
				status: "completed",
				conclusion: "failure",
				detailsUrl: null,
			},
			{
				name: "unit tests",
				status: "completed",
				conclusion: "failure",
				detailsUrl: null,
			},
